document.addEventListener(`click`,function(e){let t=e.target.closest(`[data-mle-action="debugger-toggle"]`);if(!t)return;e.preventDefault();let n=t.closest(`.mle-component`);if(!n||(n.classList.contains(`mle-debug-menu`)&&(n=n.closest(`.mle-component:not(.mle-debug-menu)`)),!n))return;let r=n.querySelector(`[data-mle-debug]`);r&&(r.classList.toggle(`hidden`),r.classList.toggle(`mle-hidden`))});